"""Parser for standard 5-field cron expressions.

Parses expressions of the form "minute hour day_of_month month day_of_week"
into a structured schedule and produces a human-readable English description.

Example:
    >>> parse_cron("0 12 * * 1-5").describe()
    'At 12:00 on Monday through Friday'
"""

from __future__ import annotations

from dataclasses import dataclass


# ---------------------------------------------------------------------------
# Field specifications
#
# Each cron field has a fixed range of legal values. Some fields also map to
# friendly names that we use when describing the schedule in English.
# ---------------------------------------------------------------------------

WEEKDAY_NAMES: list[str] = [
    "Sunday", "Monday", "Tuesday", "Wednesday",
    "Thursday", "Friday", "Saturday",
]

MONTH_NAMES: list[str] = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
]


@dataclass(frozen=True)
class FieldSpec:
    """Describes the legal values and identity of a single cron field."""

    name: str
    min_value: int
    max_value: int

    def all_values(self) -> set[int]:
        """Return every legal value for this field (used to expand '*')."""
        return set(range(self.min_value, self.max_value + 1))

    def validate(self, value: int) -> None:
        """Raise if `value` falls outside this field's legal range."""
        if not (self.min_value <= value <= self.max_value):
            raise ValueError(
                f"{self.name} value {value} is out of range "
                f"({self.min_value}-{self.max_value})"
            )


# Order matches the left-to-right order of fields in a cron expression.
FIELD_SPECS: list[FieldSpec] = [
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
]


# ---------------------------------------------------------------------------
# Parsed result types
# ---------------------------------------------------------------------------

@dataclass(frozen=True)
class CronField:
    """A single parsed field: its original text plus the values it expands to."""

    spec: FieldSpec
    raw: str
    values: frozenset[int]

    @property
    def is_wildcard(self) -> bool:
        """True when the field matches every legal value (raw '*')."""
        return self.raw == "*"

    def matches_only(self, value: int) -> bool:
        """True when the field matches exactly one specific value."""
        return self.values == frozenset({value})

    def sorted_values(self) -> list[int]:
        return sorted(self.values)


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Render this schedule as a human-readable English sentence."""
        return build_description(self)


# ---------------------------------------------------------------------------
# Top-level parsing
# ---------------------------------------------------------------------------

def parse_cron(expression: str) -> CronSchedule:
    """Parse a 5-field cron expression into a `CronSchedule`."""
    tokens = split_into_fields(expression)
    fields = [parse_field(token, spec) for token, spec in zip(tokens, FIELD_SPECS)]
    return CronSchedule(*fields)


def split_into_fields(expression: str) -> list[str]:
    """Split an expression into exactly five whitespace-separated tokens."""
    tokens = expression.split()
    if len(tokens) != len(FIELD_SPECS):
        raise ValueError(
            f"Expected {len(FIELD_SPECS)} fields, got {len(tokens)}: {expression!r}"
        )
    return tokens


# ---------------------------------------------------------------------------
# Single-field parsing
#
# A field is a comma-separated list of "parts". Each part is one of:
#   *            wildcard
#   */step       stepped wildcard
#   a            single value
#   a-b          range
#   a-b/step     stepped range
# All five fields share this grammar, so they share one parser.
# ---------------------------------------------------------------------------

def parse_field(token: str, spec: FieldSpec) -> CronField:
    """Parse one cron field into the concrete set of values it matches."""
    values: set[int] = set()
    for part in token.split(","):
        values |= parse_field_part(part, spec)
    return CronField(spec=spec, raw=token, values=frozenset(values))


def parse_field_part(part: str, spec: FieldSpec) -> set[int]:
    """Parse a single comma-separated part, applying its step if present."""
    base, step = split_step(part)
    candidates = sorted(parse_range_or_value(base, spec))
    return {value for index, value in enumerate(candidates) if index % step == 0}


def split_step(part: str) -> tuple[str, int]:
    """Split "base/step" into its components, defaulting the step to 1."""
    if "/" not in part:
        return part, 1

    base, _, step_text = part.partition("/")
    step = to_int(step_text, context="step")
    if step <= 0:
        raise ValueError(f"Step must be positive, got {step}")
    return base, step


def parse_range_or_value(base: str, spec: FieldSpec) -> set[int]:
    """Expand the non-step portion of a part: '*', a single value, or a range."""
    if base == "*":
        return spec.all_values()
    if "-" in base:
        return parse_range(base, spec)
    return {parse_single_value(base, spec)}


def parse_range(base: str, spec: FieldSpec) -> set[int]:
    """Expand a 'start-end' range into a set of validated values."""
    start_text, _, end_text = base.partition("-")
    start = parse_single_value(start_text, spec)
    end = parse_single_value(end_text, spec)
    if start > end:
        raise ValueError(f"Range start {start} is greater than end {end}")
    return set(range(start, end + 1))


def parse_single_value(text: str, spec: FieldSpec) -> int:
    """Parse and range-check a single integer value for `spec`."""
    value = to_int(text, context=spec.name)
    spec.validate(value)
    return value


def to_int(text: str, context: str) -> int:
    """Convert text to an int, raising a clear error on failure."""
    try:
        return int(text)
    except ValueError:
        raise ValueError(f"Invalid {context} value: {text!r}") from None


# ---------------------------------------------------------------------------
# Description generation
#
# The English description is assembled from independent clauses — one for the
# time of day and one for each meaningful date field — then joined together.
# ---------------------------------------------------------------------------

def build_description(schedule: CronSchedule) -> str:
    """Compose the full English description from per-field clauses."""
    clauses = [
        describe_time(schedule.minute, schedule.hour),
        describe_day_of_month(schedule.day_of_month),
        describe_month(schedule.month),
        describe_day_of_week(schedule.day_of_week),
    ]
    return " ".join(clause for clause in clauses if clause)


def describe_time(minute: CronField, hour: CronField) -> str:
    """Describe the minute and hour fields together as a time-of-day clause."""
    # Recurring-interval phrasings read more naturally than listing every value.
    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"
    if hour.is_wildcard and is_stepped_run(minute):
        return describe_minute_interval(minute)
    if minute.matches_only(0) and is_stepped_run(hour):
        return describe_hour_interval(hour)
    if hour.is_wildcard:
        return describe_minutes_past_every_hour(minute)

    return describe_explicit_times(minute, hour)


def describe_minute_interval(minute: CronField) -> str:
    """Phrase a stepped minute field, e.g. '*/15' -> 'Every 15 minutes'."""
    step = step_of(minute)
    return "Every minute" if step == 1 else f"Every {step} minutes"


def describe_hour_interval(hour: CronField) -> str:
    """Phrase a stepped hour field, e.g. '*/2' -> 'Every 2 hours, on the hour'."""
    step = step_of(hour)
    unit = "hour" if step == 1 else f"{step} hours"
    return f"Every {unit}, on the hour"


def describe_minutes_past_every_hour(minute: CronField) -> str:
    """Describe a fixed minute (or minutes) recurring within every hour."""
    minutes = [str(value) for value in minute.sorted_values()]
    return f"At {join_with_commas(minutes)} minutes past every hour"


def describe_explicit_times(minute: CronField, hour: CronField) -> str:
    """Describe specific clock times as 'At HH:MM[, HH:MM, ...]'."""
    times = [
        format_clock(hour_value, minute_value)
        for hour_value in hour.sorted_values()
        for minute_value in minute.sorted_values()
    ]
    return f"At {join_with_commas(times)}"


def describe_day_of_month(field: CronField) -> str:
    """Describe the day-of-month field, e.g. 'on the 1st of every month'."""
    if field.is_wildcard:
        return ""
    days = [ordinal(day) for day in field.sorted_values()]
    return f"on the {join_with_commas(days)} of every month"


def describe_month(field: CronField) -> str:
    """Describe the month field, e.g. 'in January and July'."""
    if field.is_wildcard:
        return ""
    names = [MONTH_NAMES[month - 1] for month in field.sorted_values()]
    return f"in {join_with_commas(names)}"


def describe_day_of_week(field: CronField) -> str:
    """Describe the day-of-week field, preferring 'X through Y' for ranges."""
    if field.is_wildcard:
        return ""

    days = field.sorted_values()
    names = [WEEKDAY_NAMES[day] for day in days]
    if is_contiguous(days) and len(days) > 2:
        return f"on {names[0]} through {names[-1]}"
    return f"on {join_with_commas(names)}"


# ---------------------------------------------------------------------------
# Small formatting and predicate helpers
# ---------------------------------------------------------------------------

def format_clock(hour: int, minute: int) -> str:
    """Format an hour/minute pair as 'HH:MM', naming midnight specially."""
    if hour == 0 and minute == 0:
        return "midnight"
    return f"{hour:02d}:{minute:02d}"


def ordinal(number: int) -> str:
    """Return the English ordinal for a number, e.g. 1 -> '1st', 22 -> '22nd'."""
    if 10 <= number % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


def join_with_commas(items: list[str]) -> str:
    """Join items into an English list: 'a', 'a and b', or 'a, b, and c'."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return f"{', '.join(items[:-1])}, and {items[-1]}"


def is_contiguous(values: list[int]) -> bool:
    """True when sorted values form an unbroken run, e.g. [1, 2, 3]."""
    return values == list(range(values[0], values[-1] + 1))


def is_stepped_run(field: CronField) -> bool:
    """True when a field is a single evenly-spaced run across its whole range.

    This recognizes both '*' (step 1) and stepped wildcards like '*/15', which
    we prefer to describe as an interval ("Every 15 minutes") rather than a list.
    """
    values = field.sorted_values()
    if len(values) < 2 or values[0] != field.spec.min_value:
        return False
    step = values[1] - values[0]
    return values == list(range(field.spec.min_value, field.spec.max_value + 1, step))


def step_of(field: CronField) -> int:
    """Return the constant step between an evenly-spaced field's values."""
    values = field.sorted_values()
    return values[1] - values[0] if len(values) >= 2 else 1


if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expression in examples:
        print(f"{expression:>15}  ->  {parse_cron(expression).describe()}")
